  'sa.confidential_help': { sq: 'Përdorni këto akomodime gjatë mësimdhënies dhe vlerësimit. Mos i ndani me askënd jashtë stafit shkollor. Sipas Ligjit 04/L-032 (Neni 40), nxënësit me NVA kanë të drejtën e akomodimeve të arsyeshme.', sr: 'Koristite ova prilagođavanja tokom nastave i ocenjivanja. Ne delite ih ni sa kim van školskog osoblja. Prema Zakonu 04/L-032 (član 40), učenici sa PIO imaju pravo na razumna prilagođavanja.', tr: 'Bu düzenlemeleri öğretim ve değerlendirme sırasında kullanın. Okul personeli dışında kimseyle paylaşmayın. 04/L-032 sayılı Kanun (Madde 40) uyarınca, özel eğitim öğrencileri makul düzenleme hakkına sahiptir.', bs: 'Koristite ova prilagođavanja tokom nastave i ocjenjivanja. Ne dijelite ih ni sa kim van školskog osoblja. Prema Zakonu 04/L-032 (član 40), učenici sa PIO imaju pravo na razumna prilagođavanja.', en: 'Use these accommodations during instruction and assessment. Do not share with anyone outside the school staff. Under Law 04/L-032 (Article 40), SEN students have the right to reasonable accommodations.' },
  'sa.no_sen_students': { sq: 'Asnjë nxënës me NVA ose PIA në klasat tuaja.', sr: 'Nema učenika sa PIO ili IOP u vašim razredima.', tr: 'Sınıflarınızda özel eğitim veya BEP olan öğrenci yok.', bs: 'Nema učenika sa PIO ili IOP u vašim razredima.', en: 'No SEN or IEP students in your classes.' },
